const shipment = {
  customer_name: $('Extract Shipment Fields').first().json.customer_name,
  customer_email: $('Extract Shipment Fields').first().json.customer_email,
  origin: $('Extract Shipment Fields').first().json.origin,
  destination: $('Extract Shipment Fields').first().json.destination,
  weight_kg: Number($('Extract Shipment Fields').first().json.weight_kg),
  mode: $('Extract Shipment Fields').first().json.mode,
  shipment_date: $('Extract Shipment Fields').first().json.shipment_date,
  cargo_type: $('Extract Shipment Fields').first().json.cargo_type
};

const carriers = [
  {
    carrier: 'BlueDart',
    rate_per_kg: Number($('Fetch BlueDart Rates').first().json['Rate_Per_Kg']) || 0,
    transit_days: $('Fetch BlueDart Rates').first().json['Transit_Days'] || 'N/A',
    reliability_score: $('Fetch BlueDart Rates').first().json['Reliability_Score'] || 'N/A',
    tracking: $('Fetch BlueDart Rates').first().json['Tracking'] || 'Yes',
    insurance: $('Fetch BlueDart Rates').first().json['Insurance'] || 'Optional'
  },
  {
    carrier: 'DTDC',
    rate_per_kg: Number($('Fetch DTDC Rates').first().json['Rate_Per_Kg']) || 0,
    transit_days: $('Fetch DTDC Rates').first().json['Transit_Days'] || 'N/A',
    reliability_score: $('Fetch DTDC Rates').first().json['Reliability_Score'] || 'N/A',
    tracking: $('Fetch DTDC Rates').first().json['Tracking'] || 'Yes',
    insurance: $('Fetch DTDC Rates').first().json['Insurance'] || 'Optional'
  },
  {
    carrier: 'Delhivery',
    rate_per_kg: Number($('Fetch Delhivery Rates').first().json['Rate_Per_Kg']) || 0,
    transit_days: $('Fetch Delhivery Rates').first().json['Transit_Days'] || 'N/A',
    reliability_score: $('Fetch Delhivery Rates').first().json['Reliability_Score'] || 'N/A',
    tracking: $('Fetch Delhivery Rates').first().json['Tracking'] || 'Yes',
    insurance: $('Fetch Delhivery Rates').first().json['Insurance'] || 'Optional'
  }
];

const enrichedCarriers = carriers.map(c => ({
  ...c,
  total_cost: Math.round(c.rate_per_kg * shipment.weight_kg)
}));

return [{ json: { shipment, carriers: enrichedCarriers } }];
